      "the_four_north_american_flyways": "🗺️ Àwọn Ọ̀nà-Òfuurufú Mẹ́rin ti North America",
      "atlantic_2": "Atlantic",
      "mississippi_2": "Mississippi",
      "central_2": "Àárín",
      "pacific_2": "Pacific",
      "when_do_birds_migrate": "📅 Ìgbà Wo Ni Àwọn Ẹyẹ Ń Ṣíkiri?",
      "migration_timing_varies_dramatically_b": "Àkókò ìṣíkiri yàtọ̀ gidigidi gẹ́gẹ́ bí ẹ̀yà:",
      "early_spring_waterfowl_ducks_geese_hea": "Ìbẹ̀rẹ̀ ìrúwé: Àwọn ẹyẹ omi (pẹ́pẹ́yẹ, ọ̀wọ́ ẹyẹ) ń lọ sí àríwá tí wọ́n ń tẹ̀lé yíyọ́ yìnyín. Red-winged Blackbirds ń padà sí àwọn ilẹ̀-ọ̀rinrin.",
      "peak_spring_warblers_vireos_tanagers_f": "Òtéńté ìrúwé: Warblers, vireos àti tanagers ń kún àríwá. Ọ̀pọ̀ àwọn ẹyẹ-orin ń ṣíkiri ní alẹ́. Ní àwọn alẹ́ òtéńté ju àwọn ẹyẹ mílíọ̀nù 500 lọ wà nínú afẹ́fẹ́.",
      "shorebirds_start_south_some_species_fa": "Àwọn ẹyẹ etíkun ń bẹ̀rẹ̀ sí gúúsù — àwọn ẹ̀yà kan “kùnà” ní àwọn ibi ìbímọ wọ́n sì bẹ̀rẹ̀ sí padà ní ìbẹ̀rẹ̀ July. Àwọn àgbà sábà máa ń kúrò ṣáájú àwọn ọmọ.",
      "peak_fall_raptors_ride_thermals_along_": "Òtéńté ìwọ́wé: Àwọn ẹyẹ ọdẹ ń gun àwọn ìṣàn ooru lẹ́gbẹ̀ẹ́ àwọn àpapọ̀ òkè. Àwọn ẹyẹ-orin ń lọ sí gúúsù tí wọ́n ń tẹ̀lé àwọn iwájú òtútù. Àwọn ọ̀wọ́ ẹyẹ ń fò ní ètò V ní alẹ́.",
      "photoperiod_day_length_is_the_primary_": "Photoperiod (gígùn ọjọ́) ni okùnfà àkọ́kọ́ ti ìṣíkiri. Bí àwọn ọjọ́ ṣe ń kúrú ní ìwọ́wé, àwọn homonu ń fa “Zugunruhe” — àìsimi ìṣíkiri — àwọn ẹyẹ sì ń bẹ̀rẹ̀ sí kó ọ̀rá jọ (ìjẹ àjẹkì), nígbà mìíràn tí wọ́n ń sọ ìwúwo ara di ìlọ́po méjì.",
      "stopover_ecology": "⛺ Ẹ̀kọ́ Àyíká Ibi Ìdúró",
      "stopovers_are_not_just_rest_stops_they": "Àwọn ibi ìdúró kì í ṣe ibi ìsinmi nìkan, wọ́n jẹ́ ",
      "refueling_stations": "àwọn ibùdó ìtún-epo-kún",
      "critical_to_survival_a_migrating_warbl": " tí ó ṣe pàtàkì fún ìwàláàyè. Warbler aṣíkiri lè lo 75% àkókò ìṣíkiri ní àwọn ibi ìdúró, tí ń jẹun lọ́nà ìwọra láti tún ọ̀rá kọ́. Ibùgbé ibi ìdúró tí ó dára lè jẹ́ ìyàtọ̀ láàrin ìyè àti ikú.",
      "at_delaware_bay_over_1_million_shorebi": "Ní Delaware Bay, ju àwọn ẹyẹ etíkun mílíọ̀nù 1 lọ (Red Knots, Ruddy Turnstones, Sanderlings) gbáralé ẹyin akán ẹṣin tí a gbé ní May. Àkókò gbọ́dọ̀ pé pérépéré: àwọn ẹyẹ ń dé gan-an ní àkókò tí àwọn akán ẹṣin ń gbé ẹyin. Bí iye àwọn akán ẹṣin bá lọ sílẹ̀ (nítorí ìpẹja àjẹkù fún ẹ̀tù), gbogbo ẹ̀wọ̀n ìṣíkiri ń wó.",
      "conservation_success_story_after_horse": "Ìtàn àṣeyọrí ìtọ́jú: Lẹ́yìn tí a fi àwọn ààlà ìkórè akán ẹṣin sílẹ̀ ní 2012, iye Red Knot bẹ̀rẹ̀ sí gbadùn díẹ̀díẹ̀ láti orí ìkéré ìdààmú ti 15,000 sí ju 50,000 lọ ní 2025.",
      "migration_physiology": "🦴 Physiology Ìṣíkiri",
      "migration_is_one_of_the_most_physicall": "Ìṣíkiri jẹ́ ọ̀kan lára àwọn iṣẹ́ tí ó béèrè agbára ara jùlọ ní ìjọba ẹranko. Àwọn ẹyẹ ń kọjá àwọn ìyípadà ara amóríyá ṣáájú kí wọ́n tó kúrò:",
      "hyperphagia": "Ìjẹ Àjẹkì",
      "before_migration_birds_enter_a_feeding": "Ṣáájú ìṣíkiri, àwọn ẹyẹ ń wọ inú ìwọra jíjẹun tí a ń pè ní ìjẹ àjẹkì, tí wọ́n ń jẹun ní ìwọ̀n ìlọ́po 2-3 ju àsìkò lọ. Blackpoll Warbler (gíráàmù 12) ń fi ọ̀rá kún ti gíráàmù 8-12, tí ó fẹ́rẹ̀ẹ́ sọ ìwúwo ara di ìlọ́po méjì. Ọ̀rá yìí ni epo fún àwọn ọkọ̀-òfuurufú láìdúró tí ó ju máìlì 2,000 lọ.",
      "organ_shrinkage": "Ìhámọ́ Ẹ̀yà Ara",
      "to_reduce_weight_migrating_birds_actua": "Láti dín ìwúwo kù, àwọn ẹyẹ aṣíkiri ń hámọ́ àwọn ẹ̀yà oúnjẹ (ìfun, ẹ̀dọ̀, àpò-oúnjẹ) dé 40% ṣáájú kí wọ́n tó kúrò. Nígbà tí wọ́n bá dé àwọn ibi ìdúró, wọ́n ń tún àwọn ẹ̀yà wọ̀nyí kọ́ kánkán láti tún-epo-kún. “Ìyíyẹ phenotype” yìí jẹ́ àrà ọ̀tọ̀ láàrin àwọn ẹranko tí ó ní ẹ̀yìn.",
      "hemoglobin": "Hemoglobin",
      "high_altitude_migrants_like_bar_headed": "Àwọn aṣíkiri gíga gíga bí Bar-headed Geese (tí ń fò ẹsẹ̀-bàtà 29,000 lórí Himalaya) ní hemoglobin pàtàkì tí ó ní ìfẹ́ púpọ̀ sí oxygen. Àwọn iṣan wọn ní myoglobin àfikún, ìdìpọ̀ capillary wọn sì jẹ́ ìlọ́po méjì ti àwọn ẹ̀yà ilẹ̀-kékeré.",
      "sleep_in_flight": "Sísùn Nínú Ọkọ̀-Òfuurufú",
      "some_birds_can_sleep_while_flying_usin": "Àwọn ẹyẹ kan lè sùn nígbà tí wọ́n ń fò, tí wọ́n ń lo “oorun ìdajì-ọpọlọ” — tí wọ́n ń pa ìdajì ọpọlọ kan lọ́gán. A ti ṣàkọsílẹ̀ Frigatebirds tí ń sùn ìṣẹ́jú 42 lọ́jọ́ nígbà àwọn ọkọ̀-òfuurufú ọjọ́ 10 ti kíkọjá òkun, tí wọ́n ń gba oorun kékeré ti ìṣẹ́jú-àáyá 12 kọ̀ọ̀kan.",
      "navigation_clock": "Aago Ìtọ́sọ́nà",
      "birds_maintain_an_internal_circadian_c": "Àwọn ẹyẹ ń tọ́jú aago circadian inú tí ó ní ìpéye amóríyá. Aago yìí ń san án fún ìṣípòpadà oòrùn ní ọ̀run (kompasi oòrùn tí a san án fún àkókò) ó sì ń tọpa àwọn ìyípadà àkókò ti gígùn ọjọ́ tí ń fa àwọn homonu ìṣíkiri.",
      "zugunruhe": "Zugunruhe",
      "zugunruhe_migration_restlessness_is_a_": "Zugunruhe (“àìsimi ìṣíkiri”) jẹ́ ipò ìhùwàsí níbi tí àwọn ẹyẹ aṣíkiri tí a fi sínú àgò ti ń lu ìyẹ́ sí ìtọ́sọ́nà tí wọn ìbá ṣíkiri lọ́nà àdánidá, ní àkókò tí wọn ìbá ṣíkiri. Ó jẹ́ èyí tí homonu ń fa a sì fi kún un ní ohun àbùdá. Kódà àwọn ẹyẹ tí a fi ọwọ́ tọ́ tí kò ní ìrírí ìṣíkiri ń fi Zugunruhe hàn.",
      "species_comparison": "📊 Ìfiwéra Ẹ̀yà",
