      "challenge_complete": "Ìpèníjà Parí!",
      "206_bones_support_protection_movement_": "Egungun 206 — àtìlẹ́yìn, ààbò, ìṣípò, ìtọ́jú ohun àlùmọ́nì, ìṣẹ̀dá ẹ̀jẹ̀.",
      "houses_meninges_brain_and_cranial_nerv": "Ó ní meninges, ọpọlọ, àti àwọn ihò iṣan orí. Àwọn ìdìpọ̀ (coronal, sagittal, lambdoid) ń darapọ̀ nígbà tí ọmọ bá pé ọdún 2.",
      "ribs_1_12": "Egungun ìhà (1-12)",
      "hyoid_bone": "Egungun Hyoid",
      "atlas_c1_axis_c2": "Atlas (C1) & Axis (C2)",
      "metatarsals_phalanges_foot": "Metatarsals & Phalanges (Ẹsẹ̀)",
      "metacarpals_phalanges_hand": "Metacarpals & Phalanges (Ọwọ́)",
      "scaphoid_bone": "Egungun Scaphoid",
      "600_muscles_movement_posture_heat_prod": "Iṣan 600+ — ìṣípò, ìdúró ara, ìṣẹ̀dá ooru, ìdúróṣinṣin oríkèé.",
      "rotator_cuff_sits": "Rotator Cuff (SITS)",
      "iliopsoas": "Iliopsoas",
      "intercostal_muscles": "Iṣan Àárín Ìhà",
      "pelvic_floor_levator_ani": "Ilẹ̀ Ìbàdí (Levator Ani)",
      "diaphragm_muscle": "Diaphragm (Iṣan)",
      "heart_60_000_miles_of_vessels_5l_of_bl": "Ọkàn, kìlómítà 60,000 ti àwọn iṣan, lítà 5 ti ẹ̀jẹ̀ — ń gbé O₂, oúnjẹ, homonu; ń yọ ìdọ̀tí kúrò.",
      "circle_of_willis": "Circle of Willis",
      "great_saphenous_vein": "Iṣan Ẹ̀jẹ̀ Saphenous Ńlá",
      "lymphatic_vessels": "Àwọn Iṣan Lymph",
      "cns_brain_spinal_cord_and_pns_31_spina": "CNS (ọpọlọ + ọ̀pá ẹ̀yìn) àti PNS (àwọn iṣan ọ̀pá ẹ̀yìn méjì-méjì 31, àwọn iṣan orí méjì-méjì 12, ètò iṣan tó ń ṣàkóso ara rẹ̀).",
      "lightest_sleep_transition_from_wakeful": "Oorun tó fúyẹ́ jù — ìyípadà láti ojúfò. Ìṣípò ojú lọ́ra, okun iṣan ń dínkù. Ìmìtìtì hypnic (ìjìgìjìgì myoclonic) wọ́pọ̀. A lè jí ẹni ní ìrọ̀rùn. Àwọn ìgbì tó mú vertex ń farahàn lórí EEG.",
      "true_sleep_begins_core_body_temperatur": "Oorun tòótọ́ bẹ̀rẹ̀. Ooru inú ara ń dínkù, ìlù ọkàn ń lọ́ra. Sleep spindles (ìbúgbàù thalamocortical) ń dáàbò bo oorun, ó sì ń mú kí ìrántí ìṣípò le. K-complexes jẹ́ àwọn ìgbì ńlá tó ń dáhùn sí ìru ìtaniji láti ẹ̀yìn.",
      "deep_slow_wave_sleep_sws_most_restorat": "Oorun jíjìn/ìgbì lọ́ra (SWS). Ìpele tó ń mú okun padà jù. Ìtújáde homonu ìdàgbà dé góńgó. Ètò glymphatic ń fọ ìdọ̀tí ọpọlọ (amyloid-β) mọ́. Ìmúkúró ìrántí ìsọ̀rọ̀ ń ṣẹlẹ̀. Ó le jù láti jí; ẹ̀rù oorun bí a bá jí ẹni.",
      "dreaming_stage_brain_is_highly_active_": "Ìpele àlá. Ọpọlọ ń ṣiṣẹ́ gidigidi (bí ojúfò) ṣùgbọ́n ara rọ (atonia nípasẹ̀ ìdíwọ́ ẹ̀ka ọpọlọ lórí àwọn iṣan ìṣípò). Ìṣípò ojú kíákíá tí ó bára mu. Ìṣàyẹ̀wò ìrántí ìmọ̀lára àti ìyanjú ìṣòro pẹ̀lú ìṣẹ̀dá. Àwọn ìyípo ń gùn síi bí alẹ́ ti ń lọ.",
      "cerebral_cortex_4_lobes": "Èèpo Ọpọlọ (Lobe 4)",
      "brodmann_areas_map_52_cytoarchitectura": "Àwọn agbègbè Brodmann ya àwòrán agbègbè 52 ti ìhun sẹ́ẹ̀lì. Èèpo ìṣípò àkọ́kọ́ (agbègbè 4), èèpo ìmọ̀lára ara àkọ́kọ́ (agbègbè 3,1,2), èèpo ìríran àkọ́kọ́ (agbègbè 17), èèpo ìgbọ́ràn àkọ́kọ́ (agbègbè 41,42). Èèpo prefrontal ni ó gbẹ̀yìn láti ní myelin (~ọdún 25).",
      "purkinje_cells_are_among_the_largest_n": "Àwọn sẹ́ẹ̀lì Purkinje wà lára àwọn iṣan tó tóbi jù, ọ̀kọ̀ọ̀kan ń gba nǹkan bí 200,000 ìtúnwọlé synaptic. Èèpo cerebellar ní ìpele 3: molecular, Purkinje, granular. Ìwádìí tuntun fi hàn ipa rẹ̀ nínú ìmọ̀, ìmọ̀lára, àti èdè.",
      "brainstem_midbrain_pons_medulla": "Ẹ̀ka Ọpọlọ (Àárín Ọpọlọ, Pons, Medulla)",
      "contains_nuclei_for_cranial_nerves_iii": "Ó ní nuclei fún àwọn iṣan orí III–XII. Ètò reticular activating (RAS) ni \"àmì ìtànná\" ọpọlọ — ìbàjẹ́ ń fa koma. Ìkọjá piramidi ní medulla: ìkọjá ìṣípò ń ṣàlàyé ìṣàkóso ìṣípò ẹ̀gbẹ́ òdìkejì.",
      "memory_replay_during_sleep_hippocampal": "Ìtúnṣe ìrántí nígbà oorun: àwọn iṣan hippocampal ń \"tún\" àwọn ìrírí ọ̀sán ṣe nígbà oorun N3, ń gbé àwọn ìrántí lọ sí neocortex. Àwọn sẹ́ẹ̀lì grid nínú èèpo entorhinal ń pèsè ìtọ́ka àyè fún àwọn sẹ́ẹ̀lì ipò hippocampal.",
      "fear_conditioning_pathway_auditory_cor": "Ọ̀nà ìkọ́ ẹ̀rù: èèpo ìgbọ́ràn → amygdala ẹ̀gbẹ́ → amygdala àárín → hypothalamus (ìdáhùn másùnmáwo) + PAG (dídúró jẹ́ẹ́). Ìbáṣepọ̀ amygdala-prefrontal ń jẹ́ kí ìṣàkóso ìmọ̀lára ṣeéṣe — ìpìlẹ̀ ìtọ́jú CBT.",
      "key_nuclei_vpl_vpm_somatosensory_relay": "Nuclei pàtàkì: VPL/VPM (ìfiránṣẹ́ ìmọ̀lára ara), LGN (ìfiránṣẹ́ ìríran sí V1), MGN (ìfiránṣẹ́ ìgbọ́ràn sí A1), pulvinar (àfiyèsí), ẹgbẹ́ nuclei iwájú (ìrántí, ìyípo Papez).",
      "thermostat_analogy_anterior_hypothalam": "Àpèjúwe thermostat: hypothalamus iwájú ń fa ìtutù (ìfẹ̀ iṣan, làágùn); hypothalamus ẹ̀yìn ń fa ooru (gbìgbọ̀n, ìhámọ́ iṣan). Ibà = góńgó tó gòkè nípasẹ̀ prostaglandin láti àrùn.",
      "split_brain_experiments_revealed_hemis": "Àwọn àdánwò pípín-ọpọlọ ṣàfihàn àkànṣe ìdajì kọ̀ọ̀kan: ìdajì òsì = èdè, ọgbọ́n; ìdajì ọ̀tún = ìṣàyẹ̀wò àyè, ti gbogbo. Ìwífún tí a fún pápá ìríran kan ni ìdajì ẹ̀gbẹ́ òdìkejì ń ṣàyẹ̀wò.",
