      "arteries_branch_into_arterioles_and_ca": "Àwọn iṣan ẹ̀jẹ̀ ń pín sí arterioles àti capillaries níbi tí a ti ń gbé O2 àti oúnjẹ tí a sì ń kó CO2/ìdọ̀tí jọ.",
      "venous_return": "Ìpadà Iṣan Ẹ̀jẹ̀",
      "deoxygenated_blood_returns_through_ven": "Ẹ̀jẹ̀ tí kò ní oxygen ń padà nípasẹ̀ venules àti àwọn iṣan, pẹ̀lú ìrànlọ́wọ́ àwọn ẹ̀rọ ìfún iṣan àti falifu, padà sí atrium ọ̀tún.",
      "path_of_air": "Ọ̀nà Afẹ́fẹ́",
      "trace_the_journey_of_a_breath_of_air_f": "Tọpa ìrìn-àjò ẹ̀mí afẹ́fẹ́ láti imú dé alveoli àti padà.",
      "nasal_cavity_2": "Ihò Imú",
      "air_enters_through_the_nostrils_and_is": "Afẹ́fẹ́ ń wọlé nípasẹ̀ àwọn ihò imú a sì ń mú u gbóná, mú u tutù, tí a sì ń sẹ́ ẹ nípasẹ̀ àwọ̀ mucous àti turbinates.",
      "pharynx_2": "Ọ̀fun",
      "air_passes_through_the_nasopharynx_and": "Afẹ́fẹ́ ń kọjá nípasẹ̀ nasopharynx àti oropharynx, ọ̀nà tí a pín pẹ̀lú ọ̀nà oúnjẹ.",
      "larynx": "Larynx",
      "air_crosses_the_vocal_cords_in_the_voi": "Afẹ́fẹ́ ń kọjá okùn ohùn nínú àpótí ohùn. Epiglottis ń dáàbò bo ọ̀nà kúrò nínú oúnjẹ wíwọ ọ̀nà afẹ́fẹ́.",
      "trachea_2": "Ọ̀nà Afẹ́fẹ́",
      "the_trachea_windpipe_is_reinforced_by_": "Ọ̀nà afẹ́fẹ́ ni a fún lókun nípasẹ̀ àwọn òrùka cartilage tó ní ìrísí C. Cilia ń gbé mucus sókè láti mú ìdọ̀tí.",
      "bronchi": "Bronchi",
      "the_trachea_splits_into_left_and_right": "Ọ̀nà afẹ́fẹ́ ń pín sí bronchi pàtàkì òsì àti ọ̀tún, ọ̀kọ̀ọ̀kan ń wọ ẹ̀dọ̀fóró kan. Wọ́n ń pín sí bronchioles kékeré.",
      "alveoli_2": "Alveoli",
      "300_million_grape_like_sacs_where_gas_": "Àpò mílíọ̀nù 300 tó dàbí èso àjàrà níbi tí ìpààrọ̀ gaasi ti ń ṣẹlẹ̀. O2 ń tàn kálẹ̀ sínú ẹ̀jẹ̀; CO2 ń tàn kálẹ̀ jáde. Ààyè ojú dọ́gba pẹ̀lú pápá tennis.",
      "exhalation": "Ìmí Jáde",
      "the_diaphragm_relaxes_and_rises_reduci": "Diaphragm ń sinmi ó sì ń gòkè, ń dín ìwọ̀n ẹ̀dọ̀fóró kù. A ń tì afẹ́fẹ́ tó ní CO2 púpọ̀ jáde nípasẹ̀ ọ̀nà kan náà ní ọ̀nà òdì.",
      "path_of_food": "Ọ̀nà Oúnjẹ",
      "follow_a_meal_from_mouth_through_the_e": "Tẹ̀lé oúnjẹ láti ẹnu kọjá gbogbo ètò oúnjẹ jíjẹ.",
      "mouth": "Ẹnu",
      "teeth_mechanically_break_food_down_sal": "Eyín ń fọ́ oúnjẹ ní ti ẹ̀rọ. Amylase itọ́ ń bẹ̀rẹ̀ oúnjẹ jíjẹ starch. Ahọ́n ń ṣe oúnjẹ di bolus.",
      "pharynx_esophagus": "Ọ̀fun & Esophagus",
      "swallowing_pushes_the_bolus_past_the_e": "Gbígbé mì ń tì bolus kọjá epiglottis. Àwọn ìgbì peristaltic ń gbé e sísàlẹ̀ esophagus cm 25 ní nǹkan bí ìṣẹ́jú-àáyá 8.",
      "gastric_acid_ph_1_5_3_5_and_pepsin_bre": "Acid ikùn (pH 1.5-3.5) àti pepsin ń fọ́ protein. Rírú ń ṣe chyme ní wákàtí 2-4.",
      "duodenum": "Duodenum",
      "the_first_25cm_of_the_small_intestine_": "Cm 25 àkọ́kọ́ ti ìfun kékeré ń gba bile láti ẹ̀dọ̀/gallbladder àti enzymes láti pancreas.",
      "jejunum_ileum": "Jejunum & Ileum",
      "most_nutrient_absorption_occurs_here_v": "Ọ̀pọ̀ gbígba oúnjẹ ń ṣẹlẹ̀ níbí nípasẹ̀ villi àti microvilli, ń mú ààyè ojú pọ̀ sí ìlọ́po 600. Gígùn mítà 6-7.",
      "water_and_electrolytes_are_reabsorbed_": "A ń tún gba omi àti electrolytes. Àwọn bakitéríà ìfun ń pọ̀n fiber tó kù, ń ṣe vitamin K àti B12.",
      "rectum_excretion": "Rectum & Ìtújáde",
